import 'dart:convert'; import 'package:shared_preferences/shared_preferences.dart'; import '../../domain/models/field_log.dart';
class FieldLogDatasource { static const key='bouh_field_logs_v12'; Future<List<FieldLog>> all() async { final prefs=await SharedPreferences.getInstance(); final raw=prefs.getString(key); if(raw==null||raw.isEmpty) return []; return (jsonDecode(raw) as List).map((e)=>FieldLog.fromJson(e)).toList(); } Future<void> add(FieldLog log) async { final prefs=await SharedPreferences.getInstance(); final logs=await all(); logs.insert(0,log); await prefs.setString(key,jsonEncode(logs.map((e)=>e.toJson()).toList())); } Future<void> clear() async { final prefs=await SharedPreferences.getInstance(); await prefs.remove(key); }}
